213→    private fun moveTrashedPostToDraft(post: PostModel) {
214→        /*
215→         * We need network connection to move a post to remote draft. We can technically move it to the local drafts
216→         * but that'll leave the trashed post in the remote which can be confusing.
217→         */
218→        if (!checkNetworkConnection.invoke()) {
219→            return
220→        }
221→        post.setStatus(DRAFT.toString())
222→        dispatcher.dispatch(PostActionBuilder.newPushPostAction(RemotePostPayload(post, site)))
223→
224→        val localPostId = LocalId(post.id)
225→        criticalPostActionTracker.add(localPostId, MOVING_POST_TO_DRAFT)
226→
227→        val snackBarHolder = SnackbarMessageHolder(
228→            message = UiStringRes(R.string.post_moving_to_draft),
229→            onDismissAction = {
230→                criticalPostActionTracker.remove(localPostId, MOVING_POST_TO_DRAFT)
231→            }
232→        )
233→        showSnackbar.invoke(snackBarHolder)
234→    }
