238→    private fun performChecksAndEdit(site: SiteModel, post: PostModel) {
239→        // first of all, check whether this post is in Conflicted state with a more recent remote version
240→        if (doesPostHaveUnhandledConflict.invoke(post)) {
241→            postListDialogHelper.showConflictedPostResolutionDialog(post)
242→            return
243→        }
244→
245→        // Then check if an autosave revision is available
246→        if (hasUnhandledAutoSave.invoke(post)) {
247→            postListDialogHelper.showAutoSaveRevisionDialog(post)
248→            return
249→        }
250→
251→        editPost(site, post)
252→    }
