254→    private fun editPost(site: SiteModel, post: PostModel) {
255→        if (UploadService.isPostUploadingOrQueued(post)) {
256→            // If the post is uploading media, allow the media to continue uploading, but don't upload the
257→            // post itself when they finish (since we're about to edit it again)
258→            UploadService.cancelQueuedPostUpload(post)
259→        }
260→        triggerPostListAction.invoke(PostListAction.EditPost(site, post, loadAutoSaveRevision = false))
261→    }
