213→    private fun moveTrashedPostToDraft(post: PostModel) {
214→        /*
215→         * We need network connection to move a post to remote draft. We can technically move it to the local drafts
216→         * but that'll leave the trashed post in the remote which can be confusing.
217→         */
218→        if (!checkNetworkConnection.invoke()) {
219→            return
220→        }
221→        post.setStatus(DRAFT.toString())
222→        dispatcher.dispatch(PostActionBuilder.newPushPostAction(RemotePostPayload(post, site)))
223→
224→        val localPostId = LocalId(post.id)
225→        criticalPostActionTracker.add(localPostId, MOVING_POST_TO_DRAFT)
226→
227→        val snackBarHolder = SnackbarMessageHolder(
228→            message = UiStringRes(R.string.post_moving_to_draft),
229→            onDismissAction = {
230→                criticalPostActionTracker.remove(localPostId, MOVING_POST_TO_DRAFT)
231→            }
232→        )
233→        showSnackbar.invoke(snackBarHolder)
234→    }
235→
236→    private fun editPostButtonAction(site: SiteModel, post: PostModel) = performChecksAndEdit(site, post)
237→
238→    private fun performChecksAndEdit(site: SiteModel, post: PostModel) {
239→        // first of all, check whether this post is in Conflicted state with a more recent remote version
240→        if (doesPostHaveUnhandledConflict.invoke(post)) {
241→            postListDialogHelper.showConflictedPostResolutionDialog(post)
242→            return
243→        }
244→
245→        // Then check if an autosave revision is available
246→        if (hasUnhandledAutoSave.invoke(post)) {
247→            postListDialogHelper.showAutoSaveRevisionDialog(post)
248→            return
249→        }
250→
251→        editPost(site, post)
252→    }
253→
254→    private fun editPost(site: SiteModel, post: PostModel) {
255→        if (UploadService.isPostUploadingOrQueued(post)) {
256→            // If the post is uploading media, allow the media to continue uploading, but don't upload the
257→            // post itself when they finish (since we're about to edit it again)
258→            UploadService.cancelQueuedPostUpload(post)
259→        }
260→        triggerPostListAction.invoke(PostListAction.EditPost(site, post, loadAutoSaveRevision = false))
261→    }
