280→    /**
281→     * This function handles a post being deleted and removed. Since deleting remote posts will trigger both delete
282→     * and remove actions we only want to remove the critical action when the post is actually successfully removed.
283→     *
284→     * It's possible to separate these into two methods that handles delete and remove. However, the fact that they
285→     * follow the same approach and the tricky nature of delete action makes combining the actions like so makes our
286→     * expectations clearer.
287→     */
288→    fun handlePostDeletedOrRemoved(localPostId: LocalId, isRemoved: Boolean, isError: Boolean) {
289→        if (criticalPostActionTracker.get(localPostId) != DELETING_POST) {
290→            /*
291→             * This is an unexpected action and either it has already been handled or another critical action has
292→             * been performed. In either case, safest action is to just ignore it.
293→             */
294→            return
295→        }
296→        if (isError) {
297→            showToast.invoke(ToastMessageHolder(R.string.error_deleting_post, Duration.SHORT))
298→        }
299→        if (isRemoved) {
300→            criticalPostActionTracker.remove(localPostId = localPostId, criticalPostAction = DELETING_POST)
301→        }
302→    }
303→
304→    fun trashPostWithLocalChanges(localPostId: Int) {
305→        // If post doesn't exist, nothing else to do
306→        val post = postStore.getPostByLocalPostId(localPostId) ?: return
307→        trashPost(post, true)
308→    }
309→
310→    fun trashPostWithUnsavedChanges(localPostId: Int) {
311→        val post = postStore.getPostByLocalPostId(localPostId) ?: return
312→        trashPost(post)
313→    }
314→
315→    private fun trashPost(post: PostModel, hasLocalChanges: Boolean = false) {
316→        // We need network connection to trash a post
317→        if (!checkNetworkConnection()) {
318→            return
319→        }
320→        val criticalPostAction = if (hasLocalChanges) {
321→            TRASHING_POST_WITH_LOCAL_CHANGES
322→        } else {
323→            TRASHING_POST
324→        }
325→
326→        showSnackbar.invoke(SnackbarMessageHolder(UiStringRes(R.string.post_trashing)))
327→        criticalPostActionTracker.add(localPostId = LocalId(post.id), criticalPostAction = criticalPostAction)
328→
329→        triggerPostUploadAction.invoke(CancelPostAndMediaUpload(post))
330→        dispatcher.dispatch(PostActionBuilder.newDeletePostAction(RemotePostPayload(post, site)))
331→    }
332→
333→    @Suppress("UseCheckOrError")
334→    fun handlePostTrashed(localPostId: LocalId, isError: Boolean) {
335→        val criticalAction = criticalPostActionTracker.get(localPostId)
336→        if (criticalAction != TRASHING_POST && criticalAction != TRASHING_POST_WITH_LOCAL_CHANGES) {
337→            /*
338→             * This is an unexpected action and either it has already been handled or another critical action has
339→             * been performed. In either case, safest action is to just ignore it.
340→             */
341→            return
342→        }
343→        criticalPostActionTracker.remove(localPostId = localPostId, criticalPostAction = criticalAction)
344→        if (isError) {
345→            showToast.invoke(ToastMessageHolder(R.string.error_deleting_post, Duration.SHORT))
346→        } else {
347→            val snackBarHolder = when (criticalAction) {
348→                TRASHING_POST -> SnackbarMessageHolder(
349→                    message = UiStringRes(R.string.post_trashed),
350→                    buttonTitle = UiStringRes(R.string.undo),
351→                    buttonAction = {
352→                        val post = postStore.getPostByLocalPostId(localPostId.value)
353→                        if (post != null) {
354→                            restorePost(post)
355→                        }
356→                    }
357→                )
358→                TRASHING_POST_WITH_LOCAL_CHANGES -> SnackbarMessageHolder(message = UiStringRes(R.string.post_trashed))
359→                else -> throw IllegalStateException("Unexpected action in handlePostTrashed(): $criticalAction")
360→            }
361→            showSnackbar.invoke(snackBarHolder)
362→        }
363→    }
364→
365→    private fun restorePost(post: PostModel) {
366→        // We need network connection to restore a post
367→        if (!checkNetworkConnection.invoke()) {
368→            return
369→        }
370→        showSnackbar.invoke(SnackbarMessageHolder(message = UiStringRes(R.string.post_restoring)))
371→        criticalPostActionTracker.add(localPostId = LocalId(post.id), criticalPostAction = RESTORING_POST)
372→        dispatcher.dispatch(PostActionBuilder.newRestorePostAction(RemotePostPayload(post, site)))
373→    }
374→
375→    fun handlePostRestored(localPostId: LocalId, isError: Boolean) {
376→        if (criticalPostActionTracker.get(localPostId) != RESTORING_POST) {
377→            /*
378→             * This is an unexpected action and either it has already been handled or another critical action has
379→             * been performed. In either case, safest action is to just ignore it.
380→             */
381→            return
382→        }
383→        criticalPostActionTracker.remove(localPostId = localPostId, criticalPostAction = RESTORING_POST)
384→        if (isError) {
385→            showToast.invoke(ToastMessageHolder(R.string.error_restoring_post, Duration.SHORT))
386→        } else {
387→            showSnackbar.invoke(SnackbarMessageHolder(message = UiStringRes(R.string.post_restored)))
388→        }
389→    }
390→
391→    fun isPerformingCriticalAction(localPostId: LocalId): Boolean {
392→        return criticalPostActionTracker.contains(localPostId)
393→    }
394→}
